# Create segmentation features
# We'll segment based on:
# 1. Spending level
# 2. Activity status
# 3. Tenure (customer lifetime)
# 4. Plan tier

# Calculate additional metrics
df['avg_monthly_spend'] = df['monthly_spend_clean']
df['tenure_months'] = df['tenure_days'] / 30

# Define spending tiers
def categorize_spending(spend):
    if spend == 0:
        return 'Zero Spend'
    elif spend < 10:
        return 'Low Spend'
    elif spend < 30:
        return 'Medium Spend'
    elif spend < 100:
        return 'High Spend'
    else:
        return 'Very High Spend'

df['spend_category'] = df['monthly_spend_clean'].apply(categorize_spending)

# Define tenure tiers
def categorize_tenure(months):
    if pd.isna(months):
        return 'Unknown'
    elif months < 3:
        return 'New (0-3m)'
    elif months < 12:
        return 'Growing (3-12m)'
    elif months < 24:
        return 'Established (1-2y)'
    else:
        return 'Veteran (2y+)'

df['tenure_category'] = df['tenure_months'].apply(categorize_tenure)

# Create customer segments based on multiple dimensions
def create_segment(row):
    is_active = row['is_active']
    spend = row['monthly_spend_clean']
    tenure = row['tenure_months']
    plan = row['plan_tier']

    # High-value segments
    if spend >= 50 and is_active:
        return 'Champions'
    elif spend >= 50 and not is_active:
        return 'At Risk High Value'

    # Medium-value active users
    elif spend >= 10 and spend < 50 and is_active:
        if pd.notna(tenure) and tenure >= 12:
            return 'Loyal Customers'
        else:
            return 'Promising'

    # Medium-value inactive users
    elif spend >= 10 and spend < 50 and not is_active:
        return 'Need Attention'

    # Low-value active users
    elif spend > 0 and spend < 10 and is_active:
        if pd.notna(tenure) and tenure < 6:
            return 'New Explorers'
        else:
            return 'Casual Users'

    # Low-value inactive users
    elif spend > 0 and spend < 10 and not is_active:
        return 'Hibernating'

    # Zero spend
    elif spend == 0 and is_active:
        return 'Free Tier Active'
    else:
        return 'Churned Free'

df['segment'] = df.apply(create_segment, axis=1)

print("Segment distribution:")
print(df['segment'].value_counts())
print("\nSegment by plan tier:")
print(pd.crosstab(df['segment'], df['plan_tier']))
